import React, { useState } from 'react';
import { FileText, Upload, Trash2, Eye, Download, Search } from 'lucide-react';
import { DocumentFile } from '../types';

const initialDocs: DocumentFile[] = [
  { id: '1', name: 'Employee_Handbook_2024.pdf', type: 'application/pdf', size: '2.4 MB', date: '2023-01-15', category: 'Policy' },
  { id: '2', name: 'Leave_Request_Form.pdf', type: 'application/pdf', size: '0.5 MB', date: '2023-05-20', category: 'Form' },
  { id: '3', name: 'IT_Security_Guidelines.pdf', type: 'application/pdf', size: '1.2 MB', date: '2023-08-10', category: 'Policy' },
  { id: '4', name: 'Sales_Performance_Q3.pdf', type: 'application/pdf', size: '3.1 MB', date: '2023-10-01', category: 'Other' },
];

const Documents: React.FC = () => {
  const [docs, setDocs] = useState<DocumentFile[]>(initialDocs);
  const [filter, setFilter] = useState('All');

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      const newDoc: DocumentFile = {
        id: Date.now().toString(),
        name: file.name,
        type: file.type,
        size: `${(file.size / 1024 / 1024).toFixed(2)} MB`,
        date: new Date().toISOString().split('T')[0],
        category: 'Other',
        url: URL.createObjectURL(file) // Create a temporary URL for preview
      };
      setDocs([newDoc, ...docs]);
    } else if (file) {
      alert("Only PDF files are allowed.");
    }
  };

  const handleDelete = (id: string) => {
    setDocs(docs.filter(d => d.id !== id));
  };

  const filteredDocs = filter === 'All' ? docs : docs.filter(d => d.category === filter);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Documents Center</h1>
          <p className="text-gray-400 text-sm">Access organizational policies, forms, and contracts.</p>
        </div>

        {/* Upload Button Wrapper */}
        <label className="flex items-center gap-2 bg-bmw-blue text-white px-4 py-2 rounded-lg cursor-pointer hover:bg-blue-600 transition-colors shadow-lg shadow-blue-900/40">
          <Upload size={18} />
          <span className="font-medium">Upload PDF</span>
          <input 
            type="file" 
            accept="application/pdf" 
            className="hidden" 
            onChange={handleFileUpload} 
          />
        </label>
      </div>

      {/* Filters & Search */}
      <div className="flex flex-col md:flex-row gap-4 bg-bmw-dark border border-bmw-gray p-4 rounded-lg items-center">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-500" size={18} />
          <input 
            type="text" 
            placeholder="Search documents..." 
            className="w-full bg-[#121212] border border-gray-700 rounded-md pl-10 pr-4 py-2 text-white text-sm focus:outline-none focus:border-bmw-blue"
          />
        </div>
        <div className="flex gap-2 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
          {['All', 'Policy', 'Contract', 'Form'].map((cat) => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              className={`px-4 py-2 rounded-md text-sm whitespace-nowrap transition-colors ${
                filter === cat 
                ? 'bg-white text-black font-semibold' 
                : 'text-gray-400 hover:text-white hover:bg-white/10'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Documents List */}
      <div className="bg-bmw-dark border border-bmw-gray rounded-lg overflow-hidden">
        <div className="grid grid-cols-12 gap-4 p-4 border-b border-gray-800 text-xs font-semibold text-gray-500 uppercase tracking-wider">
          <div className="col-span-6 md:col-span-5">Name</div>
          <div className="col-span-3 md:col-span-2 hidden md:block">Category</div>
          <div className="col-span-3 md:col-span-2 hidden md:block">Date</div>
          <div className="col-span-3 md:col-span-1 hidden md:block">Size</div>
          <div className="col-span-6 md:col-span-2 text-right">Actions</div>
        </div>

        <div className="divide-y divide-gray-800">
          {filteredDocs.length > 0 ? filteredDocs.map((doc) => (
            <div key={doc.id} className="grid grid-cols-12 gap-4 p-4 items-center hover:bg-white/5 transition-colors group">
              <div className="col-span-6 md:col-span-5 flex items-center gap-3 overflow-hidden">
                <div className="p-2 bg-red-900/20 text-red-500 rounded">
                  <FileText size={20} />
                </div>
                <span className="text-sm font-medium text-gray-200 truncate">{doc.name}</span>
              </div>
              <div className="col-span-2 hidden md:block">
                <span className="text-xs bg-gray-800 text-gray-300 px-2 py-1 rounded border border-gray-700">
                  {doc.category}
                </span>
              </div>
              <div className="col-span-2 hidden md:block text-sm text-gray-400">{doc.date}</div>
              <div className="col-span-1 hidden md:block text-sm text-gray-500 font-mono">{doc.size}</div>
              <div className="col-span-6 md:col-span-2 flex items-center justify-end gap-2">
                {doc.url && (
                  <a 
                    href={doc.url} 
                    target="_blank" 
                    rel="noreferrer"
                    className="p-2 text-gray-400 hover:text-white hover:bg-gray-700 rounded-full transition-colors"
                    title="Preview"
                  >
                    <Eye size={16} />
                  </a>
                )}
                <button className="p-2 text-gray-400 hover:text-bmw-blue hover:bg-gray-700 rounded-full transition-colors">
                  <Download size={16} />
                </button>
                <button 
                  onClick={() => handleDelete(doc.id)}
                  className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-900/20 rounded-full transition-colors"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
          )) : (
            <div className="p-12 text-center text-gray-500">
              <FileText className="mx-auto mb-4 opacity-20" size={48} />
              <p>No documents found matching this category.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Documents;

