} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface SidebarProps {
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, setIsOpen }) => {
  const navigate = useNavigate();
  const { t, language, setLanguage, dir } = useLanguage();

  const handleLogout = () => {
    // In a real app, clear auth tokens here
    navigate('/login');
  };

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'fa' : 'en');
  };

  const navItems = [
    { icon: LayoutDashboard, label: 'dashboard', path: '/' },
    { icon: User, label: 'profile', path: '/profile' },
    { icon: CreditCard, label: 'payslips', path: '/payslips' },
    { icon: FileText, label: 'documents', path: '/documents' },
    { icon: Utensils, label: 'food_order', path: '/food' },
    { icon: Ticket, label: 'support', path: '/support' },
  ];

  // Determine transform based on direction
  const hiddenTransform = dir === 'rtl' ? 'translate-x-full' : '-translate-x-full';

  return (
    <>
      {/* Mobile Overlay */}
      <div 
        className={`fixed inset-0 bg-black/50 z-40 lg:hidden transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
        onClick={() => setIsOpen(false)}
      />

      {/* Sidebar */}
      <aside 
        className={`fixed top-0 ${dir === 'rtl' ? 'right-0 border-s' : 'left-0 border-r'} h-full w-64 bg-bmw-dark border-bmw-gray z-50 transform transition-transform duration-300 ease-in-out lg:translate-x-0 ${isOpen ? 'translate-x-0' : hiddenTransform}`}
      >
        <div className="flex flex-col h-full">
          {/* Logo Area */}
          <div className="h-20 flex items-center justify-between px-6 border-b border-bmw-gray">
            <div className="flex items-center gap-2">
               <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-blue-900 to-bmw-blue flex items-center justify-center border border-white/20">
                  <span className="text-white font-bold text-xs">PK</span>
               </div>
               <span className="text-white font-semibold tracking-wide text-lg">PERSIA<span className="font-light">KHODRO</span></span>
            </div>
            <button onClick={() => setIsOpen(false)} className="lg:hidden text-gray-400 hover:text-white">
              <X size={24} />
            </button>
          </div>

          {/* Navigation */}
          <nav className="flex-1 py-6 px-3 space-y-1">
            {navItems.map((item) => (
              <NavLink
                key={item.path}
                to={item.path}
                onClick={() => setIsOpen(false)}
                className={({ isActive }) => `
                  flex items-center gap-3 px-4 py-3 rounded-md transition-all duration-200 group
                  ${isActive 
                    ? 'bg-bmw-blue text-white shadow-lg shadow-blue-900/50' 
                    : 'text-gray-400 hover:bg-bmw-gray hover:text-white'
                  }
                `}
              >
                <item.icon size={20} className="stroke-[1.5]" />
                <span className="text-sm font-medium tracking-wide">{t(item.label)}</span>
              </NavLink>
            ))}
          </nav>

          {/* Bottom Actions */}
          <div className="p-4 border-t border-bmw-gray space-y-2">
            <button 
              onClick={toggleLanguage}
              className="flex items-center gap-3 px-4 py-3 w-full text-gray-400 hover:text-white hover:bg-bmw-gray rounded-md transition-colors"
            >
              <Globe size={20} />
              <span className="text-sm font-medium">{language === 'en' ? 'فارسی' : 'English'}</span>
