  const [category, setCategory] = useState('it');
  const [priority, setPriority] = useState('medium');
  const [description, setDescription] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newTicket: TicketData = {
      id: `TK-${Math.floor(Math.random() * 1000)}`,
      subject,
      category: category as any,
      priority: priority as any,
      status: 'open',
      date: new Date().toISOString().split('T')[0],
      description
    };

    setTickets([newTicket, ...tickets]);
    setIsFormOpen(false);
    // Reset form
    setSubject('');
    setDescription('');
    setCategory('it');
    setPriority('medium');
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'open': return 'text-green-400 bg-green-900/20 border-green-800';
      case 'progress': return 'text-blue-400 bg-blue-900/20 border-blue-800';
      case 'closed': return 'text-gray-400 bg-gray-800 border-gray-700';
      default: return 'text-gray-400';
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high': return 'text-red-400';
      case 'medium': return 'text-yellow-400';
      case 'low': return 'text-blue-400';
      default: return 'text-gray-400';
