      `}>
        <form onSubmit={handleSubmit} className="p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="md:col-span-2">
             <h3 className="text-white font-bold text-lg mb-1">{t('new_ticket')}</h3>
             <p className="text-gray-500 text-xs">Please provide detailed information for faster resolution.</p>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-gray-400 text-xs mb-1 uppercase tracking-wider">{t('ticket_subject')}</label>
